#include<bits/stdc++.h>
using namespace std;
int fa[105],n,a[105],b[105];
int dfs(int x,int y)
{
	if(b[y]<b[x]) swap(x,y);
	int ans=0;
	while(b[y]!=b[x])
	{
		y=fa[y];
		ans++;
	}
	while(x!=y)
	{
		ans+=2;
		x=fa[x];
		y=fa[y];
	}
	return ans;
}
int main()
{
	cin>>n;
	b[1]=1;
	for(int i=1;i<=n;i++)
	{
		int w,u,v;
		cin>>w>>u>>v;
		fa[u]=i;
		fa[v]=i;
		a[i]=w;
		b[u]=b[v]=b[i]+1;
	}
	int minn=0x3f3f3f3f;
	for(int i=1;i<=n;i++)
	{
		int sum=0;
		for(int j=1;j<=n;j++)
		{
			if(j==i) continue;
			if(sum>=minn) break;
			sum+=(a[j]*dfs(i,j));
		}
		minn=min(minn,sum);
	}
	cout<<minn;
	return 0;
}
